var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"잠깐 기다려, 대령.","JPN":"待て、大佐。","ENG":"Wait, Colonel.","TWN":"上校，先等一下。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"뭐지, 메이슨 씨?","JPN":"何だ、メイソンさん？","ENG":"What is it, Mr. Mason?","TWN":"怎麼了，梅森？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"리플레이서의 보급창고는 코앞이야. 설마 이제 와서 겁먹은 건 아니겠지?","JPN":"リプレイサーの補給倉庫はすぐ目の前だ。\\nまさかここにきて怖気づいたんじゃないよな。","ENG":"The Replacers’ supply depot is just around the corner. Are you scared all of a sudden?","TWN":"克隆集團的補給倉庫就近在眼前，你該不會這時候突然害怕了吧？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그딴 건 아무래도 상관없어.","JPN":"そんなことはどうでもいい。","ENG":"I don’t care about the depot.","TWN":"我才懶得管什麼倉庫不倉庫的。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그보다 저 여자 대체 뭐야?! 아까부터 엄마 잃은 오리처럼 계속 따라오잖아!","JPN":"それよりあの女はいったい何だ！？\\nさっきから母親を失ったヒナみたいにずっとついてくるじゃないか！","ENG":"I mean, look at that woman! She’s following us like a duckling that lost its mom!","TWN":"我想問的是，那個女的到底想怎樣啦？！從剛剛就一直跟在我們屁股後面，活像隻失去媽媽的鴨子一樣！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"오, 오리라니…… 엄마가 없는 건 맞지만요…….","JPN":"ヒ、ヒナだなんて……親がいないのは事実ですが……","ENG":"D-duckling... Well, it’s true that I don’t have a mother...","TWN":"鴨…鴨子……我是沒有媽媽沒錯……"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"미, 미안하군…… 그런 뜻이 아니라…… ","JPN":"す、すまん……そういう意味じゃなくて……","ENG":"S-sorry about that. I didn’t mean...","TWN":"抱…抱歉……我不是這個意思……"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"아니, 제기랄! 내가 왜 사과를 하고 있는 거지?","JPN":"いや、くそったれ！　なんで俺が謝ってるんだ！","ENG":"Damn it! Why am I apologizing?","TWN":"不對啊，該死的！我幹嘛道歉啊！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"리플레이서 퀸에게 쌍둥이가 있다는 얘기는 한 번도 못 들었어. 정말 그녀인 건가?","JPN":"リプレイサー・クイーンに双子がいるなんて聞いたことがないぞ。\\n本当に彼女なのか？","ENG":"I never heard that the Replacer Queen had a twin! Or is it really her?","TWN":"我從來沒聽說過克隆·女皇是雙胞胎啊，你真的是嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"다시 말씀드리지만, 저는 리플레이서 퀸이 아니에요. 제이나 크로펠입니다.","JPN":"繰り返しますが、私はリプレイサー・クイーンではありません。ジェイナ・クロペルです。","ENG":"I told you, I’m not the Replacer Queen. I’m Jaina Kropel.","TWN":"我再說一次，我不是克隆·女皇，我是婕娜·克洛佩爾。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……아마도요.","JPN":"……たぶん、ですが。","ENG":"... I think.","TWN":"應該吧……"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"그렇다는데.","JPN":"だってさ。","ENG":"She says.","TWN":"人家剛才不是自我介紹過了嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"이름이 아니라 설명을 하라고!","JPN":"名前を聞いてるんじゃない、説明をしてほしいんだ！","ENG":"I don’t want a name, I want an explanation!","TWN":"我不是問她的名字，我是要給個說法！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>하아, 예상대로네.</color>","JPN":"<color=#ffd34c>はあ、予想どおりね。</color>","ENG":"<color=#ffd34c>*Sigh* It’s as I expected.</color>","TWN":"<color=#ffd34c>哈，果然不出我所料。</color>"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"이 목소리는…… 핑크머리 아가씨?","JPN":"この声は……ピンク頭のお嬢ちゃん？","ENG":"This voice... The pink-haired girl?","TWN":"這的聲音是……粉紅頭小姐？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"핑크머리 미녀라고 불러야지. 센스 없기는.","JPN":"ピンクヘアの美少女と呼びなさい。センス無いわね。","ENG":"Pink-haired beauty, if you please.","TWN":"是粉紅頭美女，會不會說話！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어쨌든 꽤 놀랐을 거야. 저 주먹만 센 바보가 제대로 된 설명을 해줬을 리 없으니까.","JPN":"まあ、驚いたでしょう。\\nあの力だけ強いバカが説明してるわけないもんね。","ENG":"Well, I’m sure you’re very confused by now, because that idiot is only good with his fists, not at explaining things.","TWN":"他應該很驚嚇吧？否則那個只有拳頭大顆的笨蛋，怎麼可能要求給個說法？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};